1	worker_processes auto;
2	
3	events {
4	    worker_connections 1024;
5	}
6	
7	http {
8	    upstream frontend {
9	        server frontend:3000;
10	    }
11	
12	    upstream backend {
13	        server backend:8080;
14	    }
15	
16	    server {
17	        listen 8443 ssl;
18	        server_name localhost;
19	
20	        ssl_certificate     /etc/nginx/certs/selfsigned.crt;
21	        ssl_certificate_key /etc/nginx/certs/selfsigned.key;
22	        ssl_protocols       TLSv1.2 TLSv1.3;
23	
24	        add_header Strict-Transport-Security "max-age=31536000; includeSubDomains" always;
25	        add_header X-Content-Type-Options "nosniff" always;
26	        add_header X-Frame-Options "DENY" always;
27	
28	        location /api/ {
29	            # Spring Security adds its own X-Content-Type-Options / X-Frame-Options
30	            # by default. We strip them upstream so the proxy is the single
31	            # source of truth and clients see exactly one value per header
32	            # (otherwise the test sees "nosniff, nosniff").
33	            proxy_hide_header X-Content-Type-Options;
34	            proxy_hide_header X-Frame-Options;
35	            proxy_pass http://backend;
36	            proxy_set_header Host $host;
37	            proxy_set_header X-Real-IP $remote_addr;
38	            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
39	            proxy_set_header X-Forwarded-Proto https;
40	            proxy_set_header X-Forwarded-Ssl on;
41	        }
42	
43	        location / {
44	            proxy_pass http://frontend;
45	            proxy_set_header Host $host;
46	            proxy_set_header X-Real-IP $remote_addr;
47	            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
48	            proxy_set_header X-Forwarded-Proto https;
49	            proxy_set_header X-Forwarded-Ssl on;
50	        }
51	    }
52	}
