1	package com.demo.app.application.service;
2	
3	import com.demo.app.domain.exception.ConflictException;
4	import com.demo.app.domain.exception.ResourceNotFoundException;
5	import com.demo.app.persistence.entity.AccountDeletionRequestEntity;
6	import com.demo.app.persistence.entity.UserEntity;
7	import com.demo.app.persistence.repository.AccountDeletionRequestRepository;
8	import com.demo.app.persistence.repository.UserRepository;
9	import lombok.RequiredArgsConstructor;
10	import org.slf4j.Logger;
11	import org.slf4j.LoggerFactory;
12	import org.springframework.beans.factory.annotation.Value;
13	import org.springframework.stereotype.Service;
14	import org.springframework.transaction.annotation.Transactional;
15	
16	import java.time.LocalDateTime;
17	import java.util.List;
18	
19	@Service
20	@RequiredArgsConstructor
21	public class AccountDeletionService {
22	
23	    private static final Logger log = LoggerFactory.getLogger(AccountDeletionService.class);
24	
25	    private final AccountDeletionRequestRepository deletionRepository;
26	    private final UserRepository userRepository;
27	
28	    @Value("${app.account-deletion.cooling-off-days:30}")
29	    private int coolingOffDays;
30	
31	    @Transactional
32	    public AccountDeletionRequestEntity requestDeletion(Long userId) {
33	        deletionRepository.findByUserIdAndStatus(userId, "PENDING")
34	                .ifPresent(existing -> {
35	                    throw new ConflictException("A pending deletion request already exists for this account.");
36	                });
37	
38	        AccountDeletionRequestEntity request = AccountDeletionRequestEntity.builder()
39	                .userId(userId)
40	                .status("PENDING")
41	                .requestedAt(LocalDateTime.now())
42	                .coolingOffEndsAt(LocalDateTime.now().plusDays(coolingOffDays))
43	                .build();
44	
45	        return deletionRepository.save(request);
46	    }
47	
48	    @Transactional
49	    public AccountDeletionRequestEntity cancelDeletion(Long requestId, Long userId) {
50	        AccountDeletionRequestEntity request = deletionRepository.findById(requestId)
51	                .orElseThrow(() -> new ResourceNotFoundException("Deletion request", requestId));
52	
53	        if (!request.getUserId().equals(userId)) {
54	            throw new RuntimeException("Not authorized to cancel this request");
55	        }
56	        if (!"PENDING".equals(request.getStatus())) {
57	            throw new ConflictException("Only pending requests can be cancelled");
58	        }
59	
60	        request.setStatus("CANCELLED");
61	        request.setCancelledAt(LocalDateTime.now());
62	        return deletionRepository.save(request);
63	    }
64	
65	    @Transactional
66	    public void processExpired() {
67	        List<AccountDeletionRequestEntity> expired = deletionRepository.findExpiredCoolingOff(LocalDateTime.now());
68	
69	        for (AccountDeletionRequestEntity request : expired) {
70	            UserEntity user = userRepository.findById(request.getUserId()).orElse(null);
71	            if (user != null) {
72	                // Anonymize personal data
73	                String anonymized = "deleted_" + request.getUserId();
74	                user.setUsername(anonymized);
75	                user.setEmail(anonymized + "@deleted.local");
76	                user.setDisplayName("Deleted User");
77	                user.setPasswordHash("DELETED");
78	                user.setEnabled(false);
79	                user.setUpdatedAt(LocalDateTime.now());
80	                userRepository.save(user);
81	            }
82	
83	            request.setStatus("PROCESSED");
84	            request.setProcessedAt(LocalDateTime.now());
85	            deletionRepository.save(request);
86	
87	            log.info("Processed account deletion for user {}", request.getUserId());
88	        }
89	
90	        if (!expired.isEmpty()) {
91	            log.info("Processed {} expired account deletion requests", expired.size());
92	        }
93	    }
94	
95	    public AccountDeletionRequestEntity getByUser(Long userId) {
96	        return deletionRepository.findByUserIdAndStatus(userId, "PENDING").orElse(null);
97	    }
98	}
