1	import client from './client';
2	import { Listing } from './types';
3	
4	export async function getListings(): Promise<Listing[]> {
5	  const { data } = await client.get<Listing[]>('/listings');
6	  return data;
7	}
8	
9	export async function getListingBySlug(slug: string): Promise<Listing> {
10	  const { data } = await client.get<Listing>(`/listings/slug/${slug}`);
11	  return data;
12	}
13	
14	export interface ListingSearchParams {
15	  q?: string;
16	  neighborhood?: string;
17	  lat?: number;
18	  lng?: number;
19	  radiusMiles?: number;
20	  availableAfter?: string;
21	  availableBefore?: string;
22	  minPrice?: number;
23	  maxPrice?: number;
24	  minSqft?: number;
25	  maxSqft?: number;
26	  layout?: string;
27	}
28	
29	export async function searchListings(params: ListingSearchParams = {}): Promise<Listing[]> {
30	  const { data } = await client.get<Listing[]>('/listings/search', { params });
31	  return data;
32	}
33	
34	export async function createListing(listingData: Partial<Listing>): Promise<Listing> {
35	  const { data } = await client.post<Listing>('/listings', listingData);
36	  return data;
37	}
38	
39	export async function updateListing(id: number, listingData: Partial<Listing>): Promise<Listing> {
40	  const { data } = await client.put<Listing>(`/listings/${id}`, listingData);
41	  return data;
42	}
43	
44	export async function publishListing(id: number): Promise<Listing> {
45	  const { data } = await client.post<Listing>(`/listings/${id}/publish`);
46	  return data;
47	}
48	
49	export async function archiveListing(id: number): Promise<Listing> {
50	  const { data } = await client.post<Listing>(`/listings/${id}/archive`);
51	  return data;
52	}
