1	import React, { useState, useEffect, useMemo, useCallback } from 'react';
2	import { Link } from 'react-router-dom';
3	import { getListings, searchListings, ListingSearchParams } from '@/api/listings';
4	import { getCategories } from '@/api/categories';
5	import { Listing, Category } from '@/api/types';
6	
7	const RECENT_SEARCHES_KEY = 'recentSearches';
8	const MAX_RECENT = 20;
9	
10	const ListingDiscoveryPage: React.FC = () => {
11	  const [listings, setListings] = useState<Listing[]>([]);
12	  const [categories, setCategories] = useState<Category[]>([]);
13	  const [loading, setLoading] = useState(true);
14	  const [error, setError] = useState('');
15	  const [searchQuery, setSearchQuery] = useState('');
16	  const [searchInput, setSearchInput] = useState('');
17	  const [filtersOpen, setFiltersOpen] = useState(true);
18	  const [recentSearches, setRecentSearches] = useState<string[]>(() => {
19	    try {
20	      const stored = localStorage.getItem(RECENT_SEARCHES_KEY);
21	      return stored ? JSON.parse(stored) : [];
22	    } catch {
23	      return [];
24	    }
25	  });
26	  const [filters, setFilters] = useState({
27	    minPrice: '',
28	    maxPrice: '',
29	    category: '',
30	    tag: '',
31	    publishedOnly: true,
32	    neighborhood: '',
33	    addressLat: '',
34	    addressLng: '',
35	    radiusMiles: '',
36	    minSqft: '',
37	    maxSqft: '',
38	    layout: '',
39	    availableAfter: '',
40	    availableBefore: '',
41	  });
42	  const [sortBy, setSortBy] = useState('newest');
43	
44	  useEffect(() => {
45	    const load = async () => {
46	      try {
47	        const [listingsData, categoriesData] = await Promise.all([
48	          getListings(),
49	          getCategories(),
50	        ]);
51	        setListings(listingsData);
52	        setCategories(categoriesData);
53	      } catch {
54	        setError('Failed to load listings');
55	      } finally {
56	        setLoading(false);
57	      }
58	    };
59	    load();
60	  }, []);
61	
62	  const addRecentSearch = useCallback((query: string) => {
63	    setRecentSearches((prev) => {
64	      const filtered = prev.filter((s) => s !== query);
65	      const updated = [query, ...filtered].slice(0, MAX_RECENT);
66	      localStorage.setItem(RECENT_SEARCHES_KEY, JSON.stringify(updated));
67	      return updated;
68	    });
69	  }, []);
70	
71	  const handleSearch = async (query?: string) => {
72	    const q = query ?? searchInput;
73	    setSearchQuery(q);
74	    if (q.trim()) addRecentSearch(q.trim());
75	    setLoading(true);
76	    try {
77	      const params: ListingSearchParams = {};
78	      if (q.trim()) params.q = q.trim();
79	      if (filters.neighborhood) params.neighborhood = filters.neighborhood;
80	      if (filters.addressLat && filters.addressLng) {
81	        params.lat = parseFloat(filters.addressLat);
82	        params.lng = parseFloat(filters.addressLng);
83	      }
84	      if (filters.radiusMiles) params.radiusMiles = parseFloat(filters.radiusMiles);
85	      if (filters.minPrice) params.minPrice = parseFloat(filters.minPrice);
86	      if (filters.maxPrice) params.maxPrice = parseFloat(filters.maxPrice);
87	      if (filters.minSqft) params.minSqft = parseInt(filters.minSqft);
88	      if (filters.maxSqft) params.maxSqft = parseInt(filters.maxSqft);
89	      if (filters.layout) params.layout = filters.layout;
90	      if (filters.availableAfter) params.availableAfter = filters.availableAfter;
91	      if (filters.availableBefore) params.availableBefore = filters.availableBefore;
92	      const hasParams = Object.keys(params).length > 0;
93	      const data = hasParams ? await searchListings(params) : await getListings();
94	      setListings(data);
95	    } catch {
96	      setError('Search failed');
97	    } finally {
98	      setLoading(false);
99	    }
100	  };
101	
102	  const handleSearchSubmit = (e: React.FormEvent) => {
103	    e.preventDefault();
104	    handleSearch();
105	  };
106	
107	  const handleRecentClick = (query: string) => {
108	    setSearchInput(query);
109	    handleSearch(query);
110	  };
111	
112	  const filteredAndSorted = useMemo(() => {
113	    let result = [...listings];
114	
115	    if (filters.publishedOnly) {
116	      result = result.filter((l) => l.status === 'PUBLISHED');
117	    }
118	    if (filters.minPrice) {
119	      const min = parseFloat(filters.minPrice);
120	      if (!isNaN(min)) result = result.filter((l) => l.price != null && l.price >= min);
121	    }
122	    if (filters.maxPrice) {
123	      const max = parseFloat(filters.maxPrice);
124	      if (!isNaN(max)) result = result.filter((l) => l.price != null && l.price <= max);
125	    }
126	    if (filters.category) {
127	      // Category filter uses the listing tags or productId as proxy
128	      result = result.filter((l) =>
129	        l.tags.some((t) => t.toLowerCase() === filters.category.toLowerCase())
130	      );
131	    }
132	    if (filters.tag) {
133	      const tagFilter = filters.tag.toLowerCase();
134	      result = result.filter((l) =>
135	        l.tags.some((t) => t.toLowerCase().includes(tagFilter))
136	      );
137	    }
138	
139	    switch (sortBy) {
140	      case 'price_asc':
141	        result.sort((a, b) => (a.price ?? 0) - (b.price ?? 0));
142	        break;
143	      case 'price_desc':
144	        result.sort((a, b) => (b.price ?? 0) - (a.price ?? 0));
145	        break;
146	      case 'distance':
147	        // Distance sort handled by server when lat/lng provided; no client re-sort needed
148	        break;
149	      case 'popular':
150	        result.sort((a, b) => (b.weeklyViews ?? 0) - (a.weeklyViews ?? 0));
151	        break;
152	      case 'newest':
153	      default:
154	        result.sort((a, b) => {
155	          const da = a.publishedAt ? new Date(a.publishedAt).getTime() : 0;
156	          const db = b.publishedAt ? new Date(b.publishedAt).getTime() : 0;
157	          return db - da;
158	        });
159	        break;
160	    }
161	
162	    return result;
163	  }, [listings, filters, sortBy]);
164	
165	  const trending = useMemo(() => {
166	    return [...listings]
167	      .filter((l) => l.status === 'PUBLISHED')
168	      .sort((a, b) => (b.weeklyViews ?? 0) - (a.weeklyViews ?? 0))
169	      .slice(0, 5);
170	  }, [listings]);
171	
172	  if (loading && listings.length === 0) {
173	    return <div className="page-loading">Loading listings...</div>;
174	  }
175	
176	  return (
177	    <div className="page">
178	      <div className="page-header">
179	        <h1>Discover Listings</h1>
180	      </div>
181	
182	      {error && <div className="alert alert-danger">{error}</div>}
183	
184	      <form className="search-bar" onSubmit={handleSearchSubmit}>
185	        <input
186	          type="text"
187	          className="form-input"
188	          placeholder="Search listings..."
189	          value={searchInput}
190	          onChange={(e) => setSearchInput(e.target.value)}
191	        />
192	        <button type="submit" className="btn btn-primary">Search</button>
193	      </form>
194	
195	      <div className="discovery-layout">
196	        <div className="discovery-main">
197	          <div className="flex gap-md" style={{ marginBottom: '1rem', flexWrap: 'wrap', justifyContent: 'space-between' }}>
198	            <button
199	              className="btn btn-secondary btn-sm"
200	              onClick={() => setFiltersOpen(!filtersOpen)}
201	            >
202	              {filtersOpen ? 'Hide Filters' : 'Show Filters'}
203	            </button>
204	            <div className="form-group" style={{ marginBottom: 0 }}>
205	              <select
206	                className="form-input"
207	                value={sortBy}
208	                onChange={(e) => setSortBy(e.target.value)}
209	                style={{ width: 'auto' }}
210	              >
211	                <option value="newest">Newest</option>
212	                <option value="price_asc">Price: Low to High</option>
213	                <option value="price_desc">Price: High to Low</option>
214	                <option value="popular">Most Popular</option>
215	                <option value="distance">Distance (nearest)</option>
216	              </select>
217	            </div>
218	          </div>
219	
220	          {filtersOpen && (
221	            <div className="filter-panel">
222	              <div className="filter-panel-inner">
223	                <div className="form-group">
224	                  <label className="form-label">Min Price</label>
225	                  <input
226	                    type="number"
227	                    className="form-input"
228	                    value={filters.minPrice}
229	                    onChange={(e) => setFilters({ ...filters, minPrice: e.target.value })}
230	                    placeholder="0"
231	                  />
232	                </div>
233	                <div className="form-group">
234	                  <label className="form-label">Max Price</label>
235	                  <input
236	                    type="number"
237	                    className="form-input"
238	                    value={filters.maxPrice}
239	                    onChange={(e) => setFilters({ ...filters, maxPrice: e.target.value })}
240	                    placeholder="999"
241	                  />
242	                </div>
243	                <div className="form-group">
244	                  <label className="form-label">Category</label>
245	                  <select
246	                    className="form-input"
247	                    value={filters.category}
248	                    onChange={(e) => setFilters({ ...filters, category: e.target.value })}
249	                  >
250	                    <option value="">All Categories</option>
251	                    {categories.map((c) => (
252	                      <option key={c.id} value={c.name}>{c.name}</option>
253	                    ))}
254	                  </select>
255	                </div>
256	                <div className="form-group">
257	                  <label className="form-label">Tag</label>
258	                  <input type="text" className="form-input" value={filters.tag}
259	                    onChange={(e) => setFilters({ ...filters, tag: e.target.value })} placeholder="Filter by tag" />
260	                </div>
