316	                </div>
317	                <div className="form-group">
318	                  <label className="form-label">Layout</label>
319	                  <select className="form-input" value={filters.layout}
320	                    onChange={(e) => setFilters({ ...filters, layout: e.target.value })}>
321	                    <option value="">Any</option>
322	                    <option value="studio">Studio</option>
323	                    <option value="workshop">Workshop</option>
324	                    <option value="gallery">Gallery</option>
325	                    <option value="storefront">Storefront</option>
326	                  </select>
327	                </div>
328	                <div className="form-group">
329	                  <label className="form-label">Available After</label>
330	                  <input type="date" className="form-input" value={filters.availableAfter}
331	                    onChange={(e) => setFilters({ ...filters, availableAfter: e.target.value })} />
332	                </div>
333	                <div className="form-group">
334	                  <label className="form-label">Available Before</label>
335	                  <input type="date" className="form-input" value={filters.availableBefore}
336	                    onChange={(e) => setFilters({ ...filters, availableBefore: e.target.value })} />
337	                </div>
338	                <div className="form-group">
339	                  <label className="flex gap-sm">
340	                    <input type="checkbox" checked={filters.publishedOnly}
341	                      onChange={(e) => setFilters({ ...filters, publishedOnly: e.target.checked })} />
342	                    <span className="form-label" style={{ marginBottom: 0 }}>Published only</span>
