97	    private Listing listingFromRequest(CreateListingRequest request) {
98	        return Listing.builder()
99	                .productId(request.productId())
100	                .title(request.title())
101	                .slug(request.slug())
102	                .summary(request.summary())
103	                .tags(request.tags() != null ? Arrays.asList(request.tags()) : List.of())
104	                .featured(request.featured())
105	                .neighborhood(request.neighborhood())
106	                .latitude(request.latitude())
107	                .longitude(request.longitude())
108	                .price(request.price())
109	                .sqft(request.sqft())
110	                .layout(request.layout())
111	                .availableFrom(request.availableFrom())
112	                .availableTo(request.availableTo())
