130	    private void enforceListingOwnership(Long listingId) {
131	        if (isPrivileged()) return;
132	        Listing listing = listingService.getById(listingId);
133	        Product product = productService.getById(listing.getProductId());
134	        if (!product.getSellerId().equals(getCurrentUserId())) {
135	            throw new OwnershipViolationException("You can only modify your own listings");
136	        }
137	    }
