139	    private boolean isPrivileged() {
140	        var auth = SecurityContextHolder.getContext().getAuthentication();
141	        return auth.getAuthorities().stream().anyMatch(a ->
142	                a.getAuthority().equals("ROLE_ADMINISTRATOR") ||
143	                a.getAuthority().equals("ROLE_MODERATOR"));
144	    }
