146	    private Long getCurrentUserId() {
147	        String username = SecurityContextHolder.getContext().getAuthentication().getName();
148	        return userRepository.findByUsername(username)
149	                .orElseThrow(() -> new RuntimeException("User not found"))
150	                .getId();
151	    }
