156	                l.isFeatured(), l.getViewCount(), l.getWeeklyViews(), l.getSearchRank(),
157	                l.getStatus() != null ? l.getStatus().name() : null, l.getPublishedAt(),
158	                l.getNeighborhood(), l.getLatitude(), l.getLongitude(),
159	                l.getPrice(), l.getSqft(), l.getLayout(),
160	                l.getAvailableFrom() != null ? l.getAvailableFrom().toString() : null,
161	                l.getAvailableTo() != null ? l.getAvailableTo().toString() : null);
