14	  const [actionLoading, setActionLoading] = useState(false);
15	  const [memberProfile, setMemberProfile] = useState<MemberProfile | null>(null);
16	  const [discount, setDiscount] = useState<number | null>(null);
17	
18	  useEffect(() => {
19	    if (!slug) return;
20	    const load = async () => {
21	      try {
22	        const data = await getListingBySlug(slug);
23	        setListing(data);
24	      } catch {
25	        setError('Listing not found');
26	      } finally {
27	        setLoading(false);
28	      }
29	    };
30	    load();
31	  }, [slug]);
32	
33	  useEffect(() => {
34	    if (!isAuthenticated || !user) return;
35	    if (user.role !== 'MEMBER') return;
36	
37	    const loadMember = async () => {
38	      try {
39	        const profile = await getMyProfile();
40	        setMemberProfile(profile);
41	        const packages = await getPackagesByTier(profile.tierId);
42	        for (const pkg of packages) {
43	          if (!pkg.active) continue;
44	          const items = await getItemsByPackage(pkg.id);
45	          const discountItem = items.find(
46	            (i: BenefitItem) => i.benefitType === 'DISCOUNT' || i.benefitType.toLowerCase().includes('discount')
47	          );
48	          if (discountItem) {
49	            const val = parseFloat(discountItem.benefitValue);
50	            if (!isNaN(val) && val > 0) {
51	              setDiscount(val);
52	              break;
53	            }
54	          }
55	        }
56	      } catch {
57	        // Member profile may not exist, that's fine
58	      }
59	    };
