63	  const handlePublish = async () => {
64	    if (!listing) return;
65	    setActionLoading(true);
66	    try {
67	      const updated = await publishListing(listing.id);
68	      setListing(updated);
69	    } catch {
70	      setError('Failed to publish listing');
71	    } finally {
72	      setActionLoading(false);
