1	package com.demo.app.application.service;
2	
3	import com.demo.app.domain.exception.ResourceNotFoundException;
4	import com.demo.app.persistence.entity.BenefitItemEntity;
5	import com.demo.app.persistence.entity.BenefitPackageEntity;
6	import com.demo.app.persistence.entity.MemberProfileEntity;
7	import com.demo.app.persistence.entity.ProductEntity;
8	import com.demo.app.persistence.repository.BenefitItemRepository;
9	import com.demo.app.persistence.repository.BenefitPackageRepository;
10	import com.demo.app.persistence.repository.MemberProfileRepository;
11	import com.demo.app.persistence.repository.ProductRepository;
12	import lombok.RequiredArgsConstructor;
13	import org.springframework.stereotype.Service;
14	import org.springframework.transaction.annotation.Transactional;
15	
16	import java.math.BigDecimal;
17	import java.math.RoundingMode;
18	import java.time.LocalDateTime;
19	import java.util.Comparator;
20	import java.util.HashMap;
21	import java.util.List;
22	import java.util.Map;
23	import java.util.Optional;
24	
25	/**
26	 * Authoritative server-side pricing for an order line.
27	 *
28	 * <p>Recomputes the total price from:
29	 * <ul>
30	 *     <li>The product's current unit price (DB)</li>
31	 *     <li>The buyer's tier benefits (only items in active packages for the
32	 *         buyer's tier are considered)</li>
33	 *     <li>Date-window, category, and seller scoping on each benefit item</li>
34	 *     <li>Strict non-stacking: at most one item per exclusion group, and at
35	 *         most one DISCOUNT — the highest discount wins</li>
36	 * </ul>
37	 *
38	 * <p>The client-supplied {@code totalPrice} on the inbound payload is
39	 * intentionally never read here. Pricing is server-authoritative.
40	 */
41	@Service
42	@RequiredArgsConstructor
43	@Transactional(readOnly = true)
44	public class PricingService {
45	
46	    private final ProductRepository productRepository;
47	    private final MemberProfileRepository memberProfileRepository;
48	    private final BenefitPackageRepository benefitPackageRepository;
49	    private final BenefitItemRepository benefitItemRepository;
50	
51	    public BigDecimal computeOrderTotal(Long buyerId, Long productId, int quantity) {
52	        if (quantity <= 0) {
53	            throw new IllegalArgumentException("Order quantity must be positive, got: " + quantity);
54	        }
55	
56	        ProductEntity product = productRepository.findById(productId)
57	                .orElseThrow(() -> new ResourceNotFoundException("Product", productId));
58	        BigDecimal unitPrice = product.getPrice();
59	        if (unitPrice == null) {
60	            throw new IllegalStateException("Product " + productId + " has no price configured");
61	        }
62	        BigDecimal lineSubtotal = unitPrice.multiply(BigDecimal.valueOf(quantity));
63	
64	        Long productCategoryId = product.getCategory() != null ? product.getCategory().getId() : null;
65	        Long productSellerId = product.getSeller() != null ? product.getSeller().getId() : null;
66	
67	        // Members get tier-based discounts; non-members (no profile) just pay
68	        // the line subtotal.
69	        Optional<MemberProfileEntity> profileOpt = memberProfileRepository.findByUserId(buyerId);
70	        if (profileOpt.isEmpty()) {
71	            return lineSubtotal.setScale(2, RoundingMode.HALF_UP);
72	        }
73	        MemberProfileEntity profile = profileOpt.get();
74	
75	        List<BenefitPackageEntity> packages = benefitPackageRepository.findByTierIdAndActiveTrue(profile.getTierId());
76	        LocalDateTime now = LocalDateTime.now();
77	
78	        // Collect candidate benefit items that are valid for THIS order:
79	        // active package, in-window, scoped category/seller match.
80	        java.util.List<BenefitItemEntity> applicable = new java.util.ArrayList<>();
81	        for (BenefitPackageEntity pkg : packages) {
82	            for (BenefitItemEntity item : benefitItemRepository.findByPackageId(pkg.getId())) {
83	                if (item.getValidFrom() != null && now.isBefore(item.getValidFrom())) continue;
84	                if (item.getValidTo() != null && now.isAfter(item.getValidTo())) continue;
85	                if (item.getCategoryId() != null && !item.getCategoryId().equals(productCategoryId)) continue;
86	                if (item.getSellerId() != null && !item.getSellerId().equals(productSellerId)) continue;
87	                applicable.add(item);
88	            }
89	        }
90	
91	        // Non-stacking #1: only the highest-value DISCOUNT item is applied.
92	        Optional<BenefitItemEntity> bestDiscount = applicable.stream()
93	                .filter(b -> "DISCOUNT".equalsIgnoreCase(b.getBenefitType()))
94	                .max(Comparator.comparing(this::parseBenefitValue));
95	
96	        // Non-stacking #2: within an exclusion group, only one item applies.
97	        // We pick the one that produces the largest absolute discount on this
98	        // subtotal.
99	        Map<String, BenefitItemEntity> bestPerGroup = new HashMap<>();
100	        for (BenefitItemEntity item : applicable) {
101	            String group = item.getExclusionGroup();
102	            if (group == null || group.isBlank()) continue;
103	            // The DISCOUNT category is handled separately above; don't double-count.
104	            if ("DISCOUNT".equalsIgnoreCase(item.getBenefitType())) continue;
105	            BenefitItemEntity current = bestPerGroup.get(group);
106	            if (current == null || isBetter(item, current, lineSubtotal)) {
107	                bestPerGroup.put(group, item);
108	            }
109	        }
110	
111	        BigDecimal discount = BigDecimal.ZERO;
112	        if (bestDiscount.isPresent()) {
113	            discount = discount.add(applyDiscount(bestDiscount.get(), lineSubtotal));
114	        }
115	        for (BenefitItemEntity item : bestPerGroup.values()) {
116	            discount = discount.add(applyDiscount(item, lineSubtotal));
117	        }
118	
119	        BigDecimal total = lineSubtotal.subtract(discount);
120	        if (total.signum() < 0) {
121	            total = BigDecimal.ZERO;
122	        }
123	        return total.setScale(2, RoundingMode.HALF_UP);
124	    }
125	
126	    private BigDecimal parseBenefitValue(BenefitItemEntity item) {
127	        try {
128	            return new BigDecimal(item.getBenefitValue());
129	        } catch (NumberFormatException e) {
130	            return BigDecimal.ZERO;
131	        }
132	    }
133	
134	    /**
135	     * DISCOUNT items store a percentage in benefit_value (e.g. "15" => 15%).
136	     * Other types may store a flat absolute amount; we treat any numeric
137	     * value as a flat dollar reduction. Non-numeric values reduce by zero.
138	     */
139	    private BigDecimal applyDiscount(BenefitItemEntity item, BigDecimal subtotal) {
140	        BigDecimal value = parseBenefitValue(item);
141	        if ("DISCOUNT".equalsIgnoreCase(item.getBenefitType())) {
142	            return subtotal.multiply(value).divide(BigDecimal.valueOf(100), 4, RoundingMode.HALF_UP);
143	        }
144	        return value;
145	    }
146	
147	    private boolean isBetter(BenefitItemEntity candidate, BenefitItemEntity current, BigDecimal subtotal) {
148	        return applyDiscount(candidate, subtotal).compareTo(applyDiscount(current, subtotal)) > 0;
149	    }
150	}
