events {
    worker_connections 1024;
}

http {
    # End-to-end TLS: the proxy terminates the client-facing 8443 listener
    # AND re-encrypts toward the upstreams. There is no plaintext hop
    # anywhere inside the docker network — both upstream blocks below
    # resolve to HTTPS listeners in the backend / frontend containers.
    upstream frontend {
        server frontend:3443;
    }

    upstream backend {
        server backend:8443;
    }

    server {
        listen 8443 ssl;
        server_name localhost;

        ssl_certificate     /etc/nginx/certs/selfsigned.crt;
        ssl_certificate_key /etc/nginx/certs/selfsigned.key;
        ssl_protocols       TLSv1.2 TLSv1.3;

        add_header Strict-Transport-Security "max-age=31536000; includeSubDomains" always;
        add_header X-Content-Type-Options "nosniff" always;
        add_header X-Frame-Options "DENY" always;

        location /api/ {
            # Spring Security adds its own X-Content-Type-Options / X-Frame-Options
            # by default. We strip them upstream so the proxy is the single
            # source of truth and clients see exactly one value per header
            # (otherwise the test sees "nosniff, nosniff").
            proxy_hide_header X-Content-Type-Options;
            proxy_hide_header X-Frame-Options;
            proxy_pass https://backend;
            proxy_ssl_protocols TLSv1.2 TLSv1.3;
            proxy_ssl_server_name on;
            # Self-signed upstream certs generated at image build time —
            # verification is intentionally disabled. Confidentiality of the
            # in-cluster hop is still provided by the TLS handshake.
            proxy_ssl_verify off;
            proxy_set_header Host $host;
            proxy_set_header X-Real-IP $remote_addr;
            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
            proxy_set_header X-Forwarded-Proto https;
            proxy_set_header X-Forwarded-Ssl on;
        }

        location / {
            proxy_pass https://frontend;
            proxy_ssl_protocols TLSv1.2 TLSv1.3;
            proxy_ssl_server_name on;
            proxy_ssl_verify off;
            proxy_set_header Host $host;
            proxy_set_header X-Real-IP $remote_addr;
            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
            proxy_set_header X-Forwarded-Proto https;
            proxy_set_header X-Forwarded-Ssl on;
        }
    }
}
